#include <stdio.h>
#include <stdint.h>

const int64_t MOD = 1000000007LL;

// Returns pair (F(n), F(n+1))
void fibDoubling(long long n, int64_t *fn, int64_t *fn1) {
    if (n == 0) {
        *fn = 0;
        *fn1 = 1;
        return;
    }
    int64_t a, b;
    fibDoubling(n >> 1, &a, &b); // a = F(k), b = F(k+1)
    int64_t c = (a * ((2 * b % MOD - a + MOD) % MOD)) % MOD; // F(2k)
    int64_t d = ((a * a) % MOD + (b * b) % MOD) % MOD;      // F(2k+1)
    if ((n & 1) == 0) {
        *fn = c;
        *fn1 = d;
    } else {
        *fn = d;
        *fn1 = (c + d) % MOD;
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        int64_t fn, fn1;
        fibDoubling(N + 1, &fn, &fn1);
        printf("%lld\n", fn);
    }
    return 0;
}

