#include <bits/stdc++.h>
using namespace std;
const long long MOD = 1000000007LL;

pair<long long,long long> fibDoubling(long long n){
    if(n==0) return {0,1};
    auto p = fibDoubling(n>>1);
    long long a = p.first;   // F(k)
    long long b = p.second;  // F(k+1)
    long long c = (a * ((2*b % MOD - a + MOD) % MOD)) % MOD; // F(2k)
    long long d = ((a*a)%MOD + (b*b)%MOD) % MOD;           // F(2k+1)
    if((n&1)==0) return {c,d};
    else return {d,(c+d)%MOD};
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;cin>>T;
    while(T--){
        long long N;cin>>N;
        cout<<fibDoubling(N+1).first<<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    static final long MOD = 1_000_000_007L;

    static long[] fibDoubling(long n) {
        if (n == 0) return new long[]{0, 1};
        long[] p = fibDoubling(n >> 1);
        long a = p[0]; // F(k)
        long b = p[1]; // F(k+1)
        long c = (a * ((2 * b % MOD - a + MOD) % MOD)) % MOD; // F(2k)
        long d = ((a * a) % MOD + (b * b) % MOD) % MOD;      // F(2k+1)
        if ((n & 1) == 0) return new long[]{c, d};
        else return new long[]{d, (c + d) % MOD};
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            long N = Long.parseLong(br.readLine().trim());
            long ans = fibDoubling(N + 1)[0]; // Fib(N+1)
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

