import sys
MOD = 1000000007

def fib_doubling(n):
    if n == 0:
        return (0, 1)
    a, b = fib_doubling(n >> 1)
    c = (a * ((2 * b % MOD - a + MOD) % MOD)) % MOD
    d = ((a * a) % MOD + (b * b) % MOD) % MOD
    if n & 1:
        return (d, (c + d) % MOD)
    else:
        return (c, d)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        out.append(str(fib_doubling(N + 1)[0]))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

